import type GeoJSON from 'geojson';

import { _getCanvasColor as getCanvasColor } from '@dynatrace/strato-components/charts';

import { getArcLineFeature } from './get-arc-line-feature.js';
import { getStraightLineFeature } from './get-straight-line-feature.js';
import { MAX_LINE_THICKNESS, MIN_LINE_THICKNESS } from '../../../constants.js';
import type {
  Connection,
  CurvedLine,
  FeatureProperties,
} from '../../../types/connection-layer.js';
import type { Location } from '../../../types/location.js';
import { calculateHoveredColor } from '../../../utils/calculate-hovered-color.js';
import { defineColor } from '../../../utils/define-color.js';

const getLineThickness = (thickness: number): number => {
  if (thickness < MIN_LINE_THICKNESS) {
    return MIN_LINE_THICKNESS;
  }

  if (thickness > MAX_LINE_THICKNESS) {
    return MAX_LINE_THICKNESS;
  }

  return thickness;
};

const getKeysWithNullValues = (obj: Record<string, unknown>): string[] =>
  Object.keys(obj).filter((key) => obj[key] === null);

const getFeatureProperties =
  (thickness: number, curve?: CurvedLine) =>
  <T extends Connection>(
    properties: T,
    id: string,
  ): Omit<FeatureProperties, '__lineColor' | '__lineHoveredColor'> => {
    const lineThickness = getLineThickness(thickness);

    return {
      ...properties,
      id,
      __lineWidth: lineThickness,
      __nullValues: getKeysWithNullValues(properties),
      curve,
    };
  };

const getLineFeature = (
  path: Location[],
  featureProperties: FeatureProperties,
): GeoJSON.Feature => {
  const isCurve = featureProperties.curve === 'smooth';

  if (isCurve) {
    return getArcLineFeature(path, featureProperties);
  }

  return getStraightLineFeature(path, featureProperties);
};

const getFeatures = <T extends Connection>(
  data: T[],
  thickness: number,
  color: string | ((connection: T) => string),
  curve?: CurvedLine,
): GeoJSON.Feature[] => {
  const getProperties = getFeatureProperties(thickness, curve);
  const features: GeoJSON.Feature[] = [];
  data.forEach((feature, index) => {
    if (feature.path.length >= 2) {
      const { path, ...properties } = feature;

      const featureProperties = {
        ...getProperties({ path, ...properties }, `connection-${index}`),
        ...getConnectionColor(feature, color),
      };

      features.push(getLineFeature(path, featureProperties));
    }
  });
  return features;
};

const getConnectionColor = <T extends Connection>(
  connection: T,
  color: string | ((connection: T) => string),
): Pick<FeatureProperties, '__lineColor' | '__lineHoveredColor'> => {
  const parsedColor = defineColor(color, connection);

  const canvasColor = getCanvasColor(parsedColor);
  const hoveredColor = calculateHoveredColor(canvasColor);

  return {
    __lineColor: canvasColor,
    __lineHoveredColor: hoveredColor,
  };
};

export const parseConnectionDataToGeoJSON = <T extends Connection>(
  data: T[],
  thickness: number,
  color: string | ((connection: T) => string),
  curve?: CurvedLine,
): GeoJSON.FeatureCollection => {
  return {
    type: 'FeatureCollection',

    features: getFeatures(data, thickness, color, curve),
  };
};
